mapper.select:
select distinct p.permission_code
from sys_operator_role sor
inner join sys_role r on r.id = sor.role_id and r.status = #{status}
inner join sys_role_menu rm on rm.role_id = r.id
inner join sys_menu_permission p on p.menu_id = rm.menu_id
where sor.operator_id = #{operatorId}

select distinct rm.menu_id
from sys_operator_role sor
inner join sys_role r on r.id = sor.role_id and r.status = #{status}
inner join sys_role_menu rm on rm.role_id = r.id
inner join sys_menu m on m.id = rm.menu_id and m.status = #{status}
where sor.operator_id = #{operatorId}
